// Hook : online sync via Socket.IO /game (best-effort, doesn't block UI)
function useGameSocket(roomCode: string | undefined, onState: (s: any) => void) {
  const socketRef = useRef<Socket | null>(null);
  const [connected, setConnected] = useState(false);
  useEffect(() => {
    if (!roomCode) return;
    const s = io(`${SOCKET_URL}/game`, { transports: ['websocket'], timeout: 4000 });
    socketRef.current = s;
    s.on('connect', () => {
      setConnected(true);
      log.bin(`socket /game connected → join room:${roomCode}`);
      s.emit('game:join', { roomCode });
    });
    s.on('game:state', (snapshot: any) => {
      log.bout('game:state received', { phase: snapshot?.phase });
      onState(snapshot);
    });
    s.on('disconnect', () => setConnected(false));
    s.on('connect_error', (e: any) => log.warn('socket connect_error', e?.message));
    return () => { s.disconnect(); socketRef.current = null; };
  }, [roomCode]);
  const emitMove = useCallback((action: any) => {
    socketRef.current?.emit('game:action', { roomCode, action });
  }, [roomCode]);
  return { connected, emitMove };
}

const HELP_TEXT = "Formez 14 tuiles en groupes (3+ même valeur) ou suites (3+ couleur).";
const FEEDBACK_SPECIAL = "🎉 Okey !";

export default function GameScreen() {
  const { roomCode } = useLocalSearchParams<{ roomCode: string }>();
  const router = useRouter();
  const { t } = useTranslation();
  const { palette } = useTheme();

  const [state, dispatch] = useReducer(Engine.gameReducer as any, undefined, () => {
    let s: any = (Engine as any).initGame();
    const players = [
      { id: ME,  name: 'Vous',  isBot: false },
      { id: 'b1', name: 'Bot 1', isBot: true },
      { id: 'b2', name: 'Bot 2', isBot: true },
      { id: 'b3', name: 'Bot 3', isBot: true },
    ];
    for (const p of players) s = Engine.gameReducer(s, { type: 'JOIN', playerId: p.id, playerName: p.name, isBot: p.isBot } as any);
    s = Engine.gameReducer(s, { type: 'START_GAME' } as any);
    return s;
  });

  const [moveLog, setMoveLog] = useState<any[]>([]);
  const [toast, setToast] = useState<any>(null);
  const [showQuit, setShowQuit] = useState(false);
  const [phase, setPhase] = useState<'draw' | 'discard'>('draw');
  const winner = (Engine as any).getWinner ? (Engine as any).getWinner(state) : null;
  const current = (Engine as any).getCurrentPlayer ? (Engine as any).getCurrentPlayer(state) : null;
  const isMyTurn = current?.id === ME && !winner;

  const { connected, emitMove } = useGameSocket(roomCode as any, (snap) => {
    if (snap) dispatch({ type: 'SYNC_FROM_SERVER', state: snap } as any);
  });

  useEffect(() => {
    if (winner) {
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
      setToast({ msg: FEEDBACK_SPECIAL, color: '#10B981', key: Date.now() });
      return;
    }
    if (current?.isBot && (Engine as any).botPlay) {
      const timer = setTimeout(() => {
        const action = (Engine as any).botPlay(state);
        if (action) {
          dispatch(action);
          emitMove(action);
          setMoveLog(l => [...l, { icon: '🤖', who: current.name, what: action.type.toLowerCase().replace(/_/g, ' ') }]);
        }
      }, BOT_THINK_MS);
      return () => clearTimeout(timer);
    }
  }, [state, current, winner, emitMove]);

  const me = state.players?.find((p: any) => p.id === ME);
  const myTiles = me?.hand ?? [];
  const lastDiscard = state.discardPile?.[state.discardPile.length - 1];
  const stockSize = state.stock?.length ?? 0;

  const drawFromPile = () => {
    if (!isMyTurn || phase !== 'draw') return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light).catch(() => {});
    const action = { type: 'DRAW_FROM_PILE', playerId: ME } as any;
    dispatch(action); emitMove(action);
    setPhase('discard');
    setMoveLog(l => [...l, { icon: '👤', who: 'Vous', what: 'a pioché' }]);
  };
  const drawFromDiscard = () => {
    if (!isMyTurn || phase !== 'draw') return;
    const action = { type: 'DRAW_FROM_DISCARD', playerId: ME } as any;
    dispatch(action); emitMove(action);
    setPhase('discard');
  };
  const discard = (tileId: string) => {
    if (!isMyTurn || phase !== 'discard') return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light).catch(() => {});
    const action = { type: 'DISCARD', playerId: ME, cardId: tileId } as any;
    dispatch(action); emitMove(action);
    setPhase('draw');
    setMoveLog(l => [...l, { icon: '👤', who: 'Vous', what: 'a posé' }]);
  };
  const declare = () => {
    Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
    const action = { type: 'DECLARE_WIN', playerId: ME } as any;
    dispatch(action); emitMove(action);
    setToast({ msg: FEEDBACK_SPECIAL, color: '#10B981', key: Date.now() });
  };

  const restart = () => {
    let s: any = (Engine as any).initGame();
    for (const p of [{ id: ME, name: 'Vous', isBot: false }, { id: 'b1', name: 'Bot 1', isBot: true }, { id: 'b2', name: 'Bot 2', isBot: true }, { id: 'b3', name: 'Bot 3', isBot: true }]) {
      s = Engine.gameReducer(s, { type: 'JOIN', playerId: p.id, playerName: p.name, isBot: p.isBot } as any);
    }
    s = Engine.gameReducer(s, { type: 'START_GAME' } as any);
    dispatch({ type: 'SYNC_FROM_SERVER', state: s } as any);
    setMoveLog([]); setPhase('draw');
  };

  return (
    <View style={[localStyles.root, { backgroundColor: palette.bg }]}>
      <LinearGradient colors={palette.bgGradient} style={StyleSheet.absoluteFill} />
      <AppHeader title={APP_CONFIG.name} subtitle={`Salon ${roomCode ?? '—'} ${connected ? '· 🟢' : '· 🔌'}`} showBack onBack={() => setShowQuit(true)} />

      <ScrollView contentContainerStyle={localStyles.body}>
        <AvatarRow players={state.players} currentId={current?.id} palette={palette} />
        <PhaseBanner phase={`${state.phase ?? '—'} · ${isMyTurn ? phase : ''}`} current={current} isMyTurn={isMyTurn} winner={winner} palette={palette} />
        <HelpChip palette={palette} text={HELP_TEXT} />

        {/* Stock + discard */}
        <View style={localStyles.stockRow}>
          <Pressable
            onPress={drawFromPile}
            disabled={!isMyTurn || phase !== 'draw'}
            style={[localStyles.stockBox, { borderColor: APP_CONFIG.primary, opacity: (!isMyTurn || phase !== 'draw') ? 0.5 : 1 }]}
          >
            <Ionicons name="layers" size={24} color={APP_CONFIG.primary} />
            <Text style={[localStyles.stockLabel, { color: palette.text }]}>Pioche</Text>
            <Text style={[localStyles.stockCount, { color: palette.textSecondary }]}>{stockSize}</Text>
          </Pressable>
          <Pressable
            onPress={drawFromDiscard}
            disabled={!isMyTurn || phase !== 'draw' || !lastDiscard}
            style={[localStyles.stockBox, { borderColor: palette.border, opacity: (!isMyTurn || phase !== 'draw' || !lastDiscard) ? 0.5 : 1 }]}
          >
            <Text style={[localStyles.stockLabel, { color: palette.text }]}>Défausse</Text>
            {lastDiscard ? (
              <AnimatedCard value={String(lastDiscard.value)} suit={lastDiscard.suit} width={42} height={62} facing="up" />
            ) : (
              <Text style={{ color: palette.textSecondary }}>—</Text>
            )}
          </Pressable>
          <TouchableOpacity onPress={declare} style={[localStyles.declareBtn, { backgroundColor: '#10B981' }]}>
            <Text style={localStyles.declareText}>OKEY !</Text>
            <Text style={localStyles.declareSub}>Si vous avez gagné</Text>
          </TouchableOpacity>
        </View>

        <MoveLog entries={moveLog} palette={palette} />

        <Text style={[localStyles.handTitle, { color: palette.text, marginTop: 16 }]}>
          🎴 Vos tuiles ({myTiles.length}) — {phase === 'discard' ? 'tap pour défausser' : 'piochez d\'abord'}
        </Text>
        <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={localStyles.tilesScroll}>
          {myTiles.map((c: any) => (
            <Pressable
              key={c.id}
              onPress={() => discard(c.id)}
              disabled={!isMyTurn || phase !== 'discard'}
              style={({ pressed }) => [{ opacity: !isMyTurn || phase !== 'discard' ? 0.55 : pressed ? 0.7 : 1 }]}
            >
              <AnimatedCard value={String(c.value)} suit={c.suit} width={48} height={72} facing="up" />
            </Pressable>
          ))}
        </ScrollView>
      </ScrollView>

      <FeedbackToast message={toast?.msg} visible={!!toast} color={toast?.color} key={toast?.key} />
      <WinnerModal visible={!!winner} winner={winner} onAgain={restart} onQuit={() => router.back()} palette={palette} />

      <Modal visible={showQuit} transparent animationType="fade">
        <View style={styles.modalBackdrop}>
          <View style={[styles.modalCard, { backgroundColor: palette.card, borderColor: palette.border }]}>
            <Text style={styles.modalTitle}>Quitter la partie ?</Text>
            <View style={{ flexDirection: 'row', gap: 12, marginTop: 18 }}>
              <TouchableOpacity onPress={() => setShowQuit(false)} style={[styles.modalBtn, { backgroundColor: 'rgba(255,255,255,0.15)' }]}><Text style={styles.modalBtnText}>Annuler</Text></TouchableOpacity>
              <TouchableOpacity onPress={() => { setShowQuit(false); router.back(); }} style={[styles.modalBtn, { backgroundColor: '#EF4444' }]}><Text style={styles.modalBtnText}>Quitter</Text></TouchableOpacity>
            </View>
          </View>
        </View>
      </Modal>
    </View>
  );
}

