  stockRow: { flexDirection: 'row', gap: 10, marginVertical: 10 },
  stockBox: { flex: 1, padding: 12, borderRadius: 14, borderWidth: 2, alignItems: 'center', backgroundColor: 'rgba(255,255,255,0.04)' },
