  declareBtn: { flex: 1, padding: 12, borderRadius: 14, alignItems: 'center', justifyContent: 'center' },
  declareText: { color: '#fff', fontSize: 16, fontFamily: 'Inter-Black', letterSpacing: 1 },
  declareSub: { color: 'rgba(255,255,255,0.85)', fontSize: 9, fontFamily: 'Inter-SemiBold', marginTop: 2 },
